initialList = self.view.custom.files
views = []
for image in initialList:
	settings = {
		'name': image['fileName'],
		'image': image['fileData']
	}
	views.append(settings)

return views

allData = self.view.custom.infoToSave
updateHeadData = {
	'headUUID': allData['headUUID'],
	'name': allData['headName'],
	'user': allData['user'],
	'active': allData['active']
}

updateConfigData = {
	'headUUID': allData['headUUID'],
	'headConfigUUID': allData['headConfigUUID'],
	'name': allData['headConfigName'],
	'user': allData['user'],
	'active': allData['active']
}
system.perspective.print(updateConfigData)
headResp = BlueRidge.Config.HeadConfig.updateHeadGroup(updateHeadData)
configResp = BlueRidge.Config.HeadConfig.updateHeadConfig(updateConfigData)

if headResp == -1 and configResp == -1:
	return "Saved successfully"
elif headResp == -1 and configResp != -1:
	return "Config save failed"
elif headResp != -1 and configResp == -1:
	return "Head group save failed"
else:
	return "Save failed"

